#!/bin/bash
# Downloads tree-sitter grammar source files for MC editor syntax highlighting.
# Run this script from the ts-grammars/ directory to (re)download grammar sources.
#
# Usage:
#   ./download-grammars.sh               # download all grammars
#   ./download-grammars.sh c python bash # download only selected grammars
#
# Grammar files are downloaded unmodified. All compatibility is handled by the
# compat headers in tree_sitter/ and build flags in Makefile.am.
#
# Each grammar needs at minimum:
#   - parser.c (required, generated by tree-sitter)
#   - scanner.c or scanner.cc (optional, for grammars with external scanners)
# Some grammars need additional headers — these are listed per-grammar below.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
cd "$SCRIPT_DIR"

# If arguments are provided, only download those grammars.
# Otherwise, download all.
REQUESTED_GRAMMARS="${*}"

should_download() {
    local lang="$1"
    if [ -z "$REQUESTED_GRAMMARS" ]; then
        return 0  # No filter, download all
    fi
    for g in $REQUESTED_GRAMMARS; do
        if [ "$g" = "$lang" ]; then
            return 0
        fi
    done
    return 1
}

download() {
    local lang="$1"
    should_download "$lang" || return 0

    local org="$2"
    local repo="$3"
    local branch="${4:-master}"
    local src_prefix="${5:-src}"

    echo "Downloading $lang from $org/$repo ($branch)..."

    mkdir -p "$lang"

    local base_url="https://raw.githubusercontent.com/$org/$repo/$branch/$src_prefix"

    curl -sfL "$base_url/parser.c" -o "$lang/parser.c" || {
        echo "  ERROR: Failed to download parser.c for $lang"
        rm -rf "$lang"
        return 1
    }

    # Try scanner.c (C scanner)
    if curl -sfL "$base_url/scanner.c" -o "$lang/scanner.c" 2>/dev/null; then
        echo '  Downloaded scanner.c'
    else
        rm -f "$lang/scanner.c"
    fi

    # Try scanner.cc (C++ scanner)
    if curl -sfL "$base_url/scanner.cc" -o "$lang/scanner.cc" 2>/dev/null; then
        echo '  Downloaded scanner.cc'
    else
        rm -f "$lang/scanner.cc"
    fi

    echo "  OK"
}

# Download grammar from GitLab (different URL format)
download_gitlab() {
    local lang="$1"
    should_download "$lang" || return 0

    local org="$2"
    local repo="$3"
    local branch="${4:-master}"
    local src_prefix="${5:-src}"

    echo "Downloading $lang from gitlab.com/$org/$repo ($branch)..."

    mkdir -p "$lang"

    local base_url="https://gitlab.com/$org/$repo/-/raw/$branch/$src_prefix"

    curl -sfL "$base_url/parser.c" -o "$lang/parser.c" || {
        echo "  ERROR: Failed to download parser.c for $lang"
        rm -rf "$lang"
        return 1
    }

    # Try scanner.c (C scanner)
    if curl -sfL "$base_url/scanner.c" -o "$lang/scanner.c" 2>/dev/null; then
        echo '  Downloaded scanner.c'
    else
        rm -f "$lang/scanner.c"
    fi

    echo '  OK'
}

# Helper to download an extra file into a grammar directory
download_extra() {
    local lang="$1"
    should_download "$lang" || return 0

    local org="$2"
    local repo="$3"
    local branch="$4"
    local remote_path="$5"
    local local_name="${6:-$(basename "$remote_path")}"

    local url="https://raw.githubusercontent.com/$org/$repo/$branch/$remote_path"

    curl -sfL "$url" -o "$lang/$local_name" || {
        echo "  WARNING: Failed to download extra file $remote_path for $lang"
        return 0
    }
    echo "  Downloaded $local_name"
}

