# ============================================================================
# Post-download: create stub files needed for compilation
# ============================================================================

# The perl grammar's tsp_unicode.h includes "bsearch.h" which conflicts
# with libc's bsearch function. Provide a stub that just includes stdlib.h.
if should_download perl; then
    echo 'Creating perl/bsearch.h stub...'
    cat > perl/bsearch.h << 'STUB'
/* Stub: perl grammar's tsp_unicode.h includes "bsearch.h" but we only
   need the standard library bsearch() which is in stdlib.h. */
#include <stdlib.h>
STUB
fi

echo ''
echo 'Done. Downloaded grammars for $(ls -d */ 2>/dev/null | wc -l) languages.'
echo ''
echo 'Grammar files are unmodified. All compatibility is handled by:'
echo '  tree_sitter/parser.h  -- compat header (REDUCE macro, TSFieldMapSlice, etc.)'
echo '  Makefile.am           -- include paths, warning suppression'
echo '  perl/bsearch.h        -- stub for libc conflict'
